      taskDescription: description,
      adminNote: body.adminNote ?? null,
      sourceInput: body.sourceInput ?? null,

      assigneeEmail: body.assigneeEmail ?? body.assignedTo ?? null,
      managerEmail: body.managerEmail,
      ownerName: body.ownerName,

      priority: body.priority,
      status: body.status,
      eventType: body.eventType ?? null,
      eventMessage: body.eventMessage ?? null,

      deadline: deadlineDate?.toISOString() ?? deadlineRaw ?? null,
      deadlineDisplay:
        formatDate(deadlineRaw) ??
        (typeof deadlineRaw === 'string' ? deadlineRaw : null) ??
        'Chưa có deadline',

      createdAt: createdDate?.toISOString() ?? body.createdAt ?? null,
      createdAtDisplay: formatDate(body.createdAt),

      completedAt: completedDate?.toISOString() ?? null,
