      `✅ Task da hoan thanh: ${$json.doneCount ?? '-'}`,
      `🕒 Thoi diem chup: ${new Date().toLocaleString('vi-VN')}`
    ].join('\n')
  }
}];

const items = $input.all().map((entry) => entry.json ?? {});
const normalize = (value) => String(value || '').trim().toUpperCase().replace(/[\s-]+/g, '_');

const totalOpen = items.length;
const highPriorityCount = items.filter((item) => normalize(item.priority) === 'HIGH').length;
const inProgressCount = items.filter((item) => normalize(item.status) === 'IN_PROGRESS').length;
const doneCount = items.filter((item) => normalize(item.status) === 'DONE').length;
const overdueCount = items.filter((item) => normalize(item.status) === 'OVERDUE').length;

const assigneeCounts = {};
for (const item of items) {
  const assignee = item.assigneeEmail || item.ownerName || 'Chua ro';
  assigneeCounts[assignee] = (assigneeCounts[assignee] || 0) + 1;
}

const topAssignee = Object.entries(assigneeCounts).sort((a, b) => b[1] - a[1])[0] || null;
const topAssigneeLabel = topAssignee ? `${topAssignee[0]} (${topAssignee[1]})` : '-';

const focusTasks = [...items]
  .filter((item) => ['OVERDUE', 'IN_PROGRESS', 'PENDING'].includes(normalize(item.status)))
  .sort((a, b) => {
    const priorityRank = { HIGH: 0, MEDIUM: 1, LOW: 2 };
    const aPriority = priorityRank[normalize(a.priority)] ?? 9;
    const bPriority = priorityRank[normalize(b.priority)] ?? 9;
    if (aPriority !== bPriority) return aPriority - bPriority;
    const aDeadline = Date.parse(a.deadline || '') || Number.MAX_SAFE_INTEGER;
    const bDeadline = Date.parse(b.deadline || '') || Number.MAX_SAFE_INTEGER;
    return aDeadline - bDeadline;
  })
  .slice(0, 3)
  .map((item) => ({
    taskId: item.taskId || null,
    taskName: item.taskName || null,
    assigneeEmail: item.assigneeEmail || null,
    status: item.status || null,
    deadline: item.deadline || null,
    deadlineDisplay: item.deadlineDisplay || item.deadline || null
  }));

return [{
  json: {
    items,
    totalOpen,
    highPriorityCount,
    inProgressCount,
    doneCount,
    overdueCount,
    topAssigneeLabel,
    focusTasks,
    snapshotAt: items[0]?.snapshotAt || new Date().toISOString()
  }
}];

const snapshotAt = new Date().toISOString();
return $input.all().map((entry) => ({
  json: {
    ...(entry.json ?? {}),
    snapshotAt
  }
}));

const snapshotAt = $json.snapshotAt || new Date().toISOString();
const focusTasks = Array.isArray($json.focusTasks) ? $json.focusTasks : [];

const formatStatus = (status) => {
  const value = String(status || '').toUpperCase();
  if (value === 'IN_PROGRESS') return 'Dang xu ly';
  if (value === 'OVERDUE') return 'Qua han';
  if (value === 'DONE') return 'Da hoan thanh';
  if (value === 'PENDING') return 'Cho xu ly';
  return status || '-';
};

const lines = [
  '📊 BAO CAO HE THONG CUOI NGAY',
  '',
  `📂 Tong task dang mo: ${$json.totalOpen ?? 0}`,
  `🚨 Task qua han: ${$json.overdueCount ?? 0}`,
  `⚙️ Dang xu ly: ${$json.inProgressCount ?? 0}`,
  `✅ Da hoan thanh: ${$json.doneCount ?? 0}`,
  `🔥 Uu tien cao: ${$json.highPriorityCount ?? 0}`,
  `👤 Nhieu task nhat: ${$json.topAssigneeLabel || '-'}`,
  `🕒 Thoi diem chup: ${snapshotAt}`
];

if (focusTasks.length) {
  lines.push('');
  lines.push('🎯 TASK CAN CHU Y:');
  focusTasks.forEach((task, index) => {
    lines.push(
      `${index + 1}. ${task.taskName || '-'} | ${task.assigneeEmail || '-'} | ${formatStatus(task.status)} | ${task.deadlineDisplay || task.deadline || '-'}`
    );
  });
}

return [{
  json: {
    ...$json,
    fileContent: lines.join('\n')
  }
}];

const parseDate = (value) => {
  if (!value) return null;
  if (Array.isArray(value)) {
    const [year, month = 1, day = 1, hour = 0, minute = 0, second = 0, nano = 0] = value;
    const millis = Math.floor(Number(nano) / 1000000);
    const date = new Date(year, month - 1, day, hour, minute, second, millis);
    return Number.isNaN(date.getTime()) ? null : date;
  }
  const date = new Date(value);
  return Number.isNaN(date.getTime()) ? null : date;
};

const formatDate = (date) => {
  if (!date) return null;
  const pad = (input) => String(input).padStart(2, '0');
  return `${pad(date.getDate())}/${pad(date.getMonth() + 1)}/${date.getFullYear()} ${pad(date.getHours())}:${pad(date.getMinutes())}`;
};

const normalize = (value) => String(value || '').trim().toUpperCase().replace(/[\s-]+/g, '_');
const snapshotAt = new Date().toISOString();

return $input.all().map((entry) => {
  const item = entry.json ?? {};
  const deadline = parseDate(item.deadline);
  const completedAt = parseDate(item.completedAt);
  const assigneeEmail = item.assigneeEmail || 'chua-phan-cong';

  return {
    json: {
      ...item,
      assigneeEmail,
      assigneeLabel: assigneeEmail === 'chua-phan-cong' ? 'Chua phan cong' : assigneeEmail,
      priority: normalize(item.priority),
      status: normalize(item.status),
      deadline: deadline?.toISOString() ?? item.deadline ?? null,
      deadlineDisplay: item.deadlineDisplay ?? formatDate(deadline) ?? 'Chua co deadline',
      completedAt: completedAt?.toISOString() ?? item.completedAt ?? null,
      completedAtDisplay: completedAt ? formatDate(completedAt) : null,
      snapshotAt
    }
  };
});

const items = $input.all().map((entry) => entry.json ?? {});
const groups = {};
const now = Date.now();
const openStatuses = new Set(['PENDING', 'TODO', 'IN_PROGRESS', 'IN_REVIEW', 'OVERDUE']);

for (const item of items) {
  const key = item.assigneeEmail || 'chua-phan-cong';
  const deadlineValue = item.deadline ? Date.parse(item.deadline) : NaN;
  const completedValue = item.completedAt ? Date.parse(item.completedAt) : NaN;
  const hasDeadline = !Number.isNaN(deadlineValue);
  const hasCompleted = !Number.isNaN(completedValue);
  const daysToDeadline = hasDeadline ? Math.ceil((deadlineValue - now) / 86400000) : null;
  const isOpen = openStatuses.has(item.status);
  const isDoneThisWeek = item.status === 'DONE' && hasCompleted;
  const isOnTime = isDoneThisWeek && hasDeadline && completedValue <= deadlineValue;
  const isEarly = isDoneThisWeek && hasDeadline && completedValue < deadlineValue;
  const isLate = isDoneThisWeek && hasDeadline && completedValue > deadlineValue;

  if (!groups[key]) {
    groups[key] = {
      assigneeEmail: key,
      assigneeLabel: item.assigneeLabel || key,
      snapshotAt: item.snapshotAt || new Date().toISOString(),
      totalOpenTasks: 0,
      overdueCount: 0,
      nearDeadlineCount: 0,
      highPriorityCount: 0,
      doneThisWeek: 0,
      onTimeDoneCount: 0,
      assessedDoneCount: 0,
      earlyDoneCount: 0,
      lateDoneCount: 0,
      focusTasks: []
    };
  }

  const employee = groups[key];

  if (isOpen) {
    employee.totalOpenTasks += 1;
    if (item.status === 'OVERDUE') employee.overdueCount += 1;
    if (item.priority === 'HIGH') employee.highPriorityCount += 1;
    if (daysToDeadline !== null && daysToDeadline >= 0 && daysToDeadline <= 2) employee.nearDeadlineCount += 1;

    employee.focusTasks.push({
      taskId: item.taskId || '-',
      taskName: item.taskName || '-',
      status: item.status || '-',
      priority: item.priority || '-',
      deadlineDisplay: item.deadlineDisplay || item.deadline || '-'
    });
  }

  if (isDoneThisWeek) {
    employee.doneThisWeek += 1;
    if (hasDeadline) {
      employee.assessedDoneCount += 1;
      if (isOnTime) employee.onTimeDoneCount += 1;
      if (isEarly) employee.earlyDoneCount += 1;
      if (isLate) employee.lateDoneCount += 1;
    }
  }
}

const employees = Object.values(groups)
  .map((employee) => {
    const onTimeRate = employee.assessedDoneCount > 0
      ? Math.round((employee.onTimeDoneCount / employee.assessedDoneCount) * 100)
      : 0;

    return {
      ...employee,
      onTimeRate,
      alertLevel: employee.overdueCount >= 2 || employee.lateDoneCount >= 2 || employee.totalOpenTasks >= 6 || employee.nearDeadlineCount >= 3 ? 'OVERLOADED' : 'NORMAL',
      focusTasks: employee.focusTasks
        .sort((a, b) => {
          const statusRank = { OVERDUE: 0, IN_PROGRESS: 1, IN_REVIEW: 2, PENDING: 3, TODO: 4 };
          const priorityRank = { HIGH: 0, MEDIUM: 1, LOW: 2 };
          const aStatus = statusRank[a.status] ?? 9;
          const bStatus = statusRank[b.status] ?? 9;
          if (aStatus !== bStatus) return aStatus - bStatus;
          return (priorityRank[a.priority] ?? 9) - (priorityRank[b.priority] ?? 9);
        })
        .slice(0, 2)
    };
  });

const topEarlyEmployees = [...employees]
  .filter((employee) => employee.earlyDoneCount > 0 || employee.doneThisWeek > 0)
  .sort((a, b) => {
    if (b.earlyDoneCount !== a.earlyDoneCount) return b.earlyDoneCount - a.earlyDoneCount;
    if (b.onTimeRate !== a.onTimeRate) return b.onTimeRate - a.onTimeRate;
    return b.doneThisWeek - a.doneThisWeek;
  })
  .slice(0, 3);

const topRiskEmployees = [...employees]
  .filter((employee) => employee.overdueCount > 0 || employee.lateDoneCount > 0 || employee.totalOpenTasks > 0)
  .sort((a, b) => {
    if (b.overdueCount !== a.overdueCount) return b.overdueCount - a.overdueCount;
    if (b.lateDoneCount !== a.lateDoneCount) return b.lateDoneCount - a.lateDoneCount;
    if (b.nearDeadlineCount !== a.nearDeadlineCount) return b.nearDeadlineCount - a.nearDeadlineCount;
    return b.totalOpenTasks - a.totalOpenTasks;
  })
  .slice(0, 3);

const totals = employees.reduce((acc, employee) => {
  acc.totalOpenTasks += employee.totalOpenTasks;
  acc.overdueCount += employee.overdueCount;
  acc.nearDeadlineCount += employee.nearDeadlineCount;
  acc.highPriorityCount += employee.highPriorityCount;
  acc.doneThisWeek += employee.doneThisWeek;
  acc.earlyDoneCount += employee.earlyDoneCount;
  acc.lateDoneCount += employee.lateDoneCount;
  acc.assessedDoneCount += employee.assessedDoneCount;
  acc.onTimeDoneCount += employee.onTimeDoneCount;
  return acc;
}, {
  totalOpenTasks: 0,
  overdueCount: 0,
  nearDeadlineCount: 0,
  highPriorityCount: 0,
  doneThisWeek: 0,
  earlyDoneCount: 0,
  lateDoneCount: 0,
  assessedDoneCount: 0,
  onTimeDoneCount: 0
});

return [{
  json: {
    snapshotAt: employees[0]?.snapshotAt || new Date().toISOString(),
    totalEmployees: employees.length,
    totalOpenTasks: totals.totalOpenTasks,
    overdueCount: totals.overdueCount,
    nearDeadlineCount: totals.nearDeadlineCount,
    highPriorityCount: totals.highPriorityCount,
    doneThisWeek: totals.doneThisWeek,
    earlyDoneCount: totals.earlyDoneCount,
    lateDoneCount: totals.lateDoneCount,
    onTimeRate: totals.assessedDoneCount > 0 ? Math.round((totals.onTimeDoneCount / totals.assessedDoneCount) * 100) : 0,
    overloadedCount: employees.filter((employee) => employee.alertLevel === 'OVERLOADED').length,
    topEarlyEmployees,
    topRiskEmployees,
    employees
  }
}];

const topEarlyEmployees = Array.isArray($json.topEarlyEmployees) ? $json.topEarlyEmployees : [];
const topRiskEmployees = Array.isArray($json.topRiskEmployees) ? $json.topRiskEmployees : [];

const lines = [
  '📈 BAO CAO THONG KE NHAN VIEN',
  '',
  `👥 Nhan vien co task: ${$json.totalEmployees ?? 0}`,
  `📂 Task dang mo: ${$json.totalOpenTasks ?? 0}`,
  `🚨 Task qua han: ${$json.overdueCount ?? 0}`,
  `⏳ Task gan deadline: ${$json.nearDeadlineCount ?? 0}`,
  `🔥 Task uu tien cao: ${$json.highPriorityCount ?? 0}`,
