  `🏁 Hoan thanh som: ${$json.earlyDoneCount ?? 0}`,
  `🔴 Hoan thanh tre: ${$json.lateDoneCount ?? 0}`,
  `🎯 Ty le dung han: ${$json.onTimeRate ?? 0}%`,
  `🕒 Thoi diem thong ke: ${$json.snapshotAt || new Date().toISOString()}`
];

if (topEarlyEmployees.length) {
  lines.push('');
  lines.push('🌟 NHAN VIEN HOAN THANH SOM:');
  topEarlyEmployees.forEach((employee, index) => {
    lines.push(`${index + 1}. ${employee.assigneeLabel || '-'} | Som ${employee.earlyDoneCount} | Dung han ${employee.onTimeRate}% | Xong tuan nay ${employee.doneThisWeek}`);
  });
}

if (topRiskEmployees.length) {
  lines.push('');
  lines.push('⚠️ NHAN VIEN HAY BI QUA HAN:');
  topRiskEmployees.forEach((employee, index) => {
    lines.push(`${index + 1}. ${employee.assigneeLabel || '-'} | Qua han ${employee.overdueCount} | Tre ${employee.lateDoneCount} | Dang mo ${employee.totalOpenTasks}`);
  });
}

return [{
  json: {
    ...$json,
    employeeReport: lines.join('\n')
  }
}];

const now = new Date().toISOString();
const overloaded = ($json.alertLevel || 'NORMAL') === 'OVERLOADED';

return [{
  json: {
    ...$json,
    taskId: 'EMPLOYEE_STATS',
    taskName: `Stats ${$json.assigneeLabel || $json.assigneeEmail || 'Unknown'}`,
    priority: `${$json.highPriorityCount ?? 0} HIGH | ${$json.onTimeRate ?? 0}% ONTIME`,
    status: overloaded ? 'AT_RISK' : ($json.earlyDoneCount > 0 ? 'PERFORMING' : 'STABLE'),
    deadline: $json.snapshotAt || now,
    createdAt: now,
    alertLevel: overloaded ? 'OVERLOADED' : 'NORMAL'
  }
}];

const parseDate = (value) => {
  if (!value) return null;

  if (Array.isArray(value)) {
    const [year, month = 1, day = 1, hour = 0, minute = 0, second = 0, nano = 0] = value;
    const millis = Math.floor(Number(nano) / 1000000);
    const date = new Date(year, month - 1, day, hour, minute, second, millis);
    return Number.isNaN(date.getTime()) ? null : date;
  }

  const date = new Date(value);
  return Number.isNaN(date.getTime()) ? null : date;
};

const formatDate = (value) => {
  const date = parseDate(value);
  if (!date) return null;

  const pad = (input) => String(input).padStart(2, '0');
  return pad(date.getDate()) + '/' + pad(date.getMonth() + 1) + '/' + date.getFullYear() + ' ' + pad(date.getHours()) + ':' + pad(date.getMinutes());
};

const task = $json;
const status = String(task.status || '').toUpperCase();
const itemType = String(task.itemType || (task.subtaskId ? 'SUBTASK' : 'TASK')).toUpperCase();
const lineBreak = String.fromCharCode(10);

if (itemType === 'SUBTASK' || task.subtaskId) {
  return [];
}

if (task.eventType && task.eventType !== 'TASK_CREATED') {
  return [];
}

if (status && !['PENDING', 'TODO'].includes(status)) {
  return [];
}

const subtasks = Array.isArray(task.subtasks) ? task.subtasks : [];
const assignmentMap = {};

if (task.assigneeEmail) {
  assignmentMap[task.assigneeEmail] = {
    email: task.assigneeEmail,
    isMainAssignee: true,
    subtasks: []
  };
}

for (const subtask of subtasks) {
  const email =
    subtask.assignedTo ??
    subtask.assigned_to ??
    subtask.assigneeEmail ??
    subtask.assignee_email;

  if (!email) continue;

  if (!assignmentMap[email]) {
    assignmentMap[email] = {
      email,
      isMainAssignee: false,
      subtasks: []
    };
  }

  const subDeadlineRaw = subtask.deadline ?? subtask.dueDate ?? subtask.endDate;

  assignmentMap[email].subtasks.push({
    id: subtask.id ?? null,
    title: subtask.title ?? subtask.name ?? 'Subtask chưa có tên',
    deadline: parseDate(subDeadlineRaw)?.toISOString() ?? subDeadlineRaw ?? null,
    deadlineDisplay:
      subtask.deadlineDisplay ??
      formatDate(subDeadlineRaw) ??
      subDeadlineRaw ??
      'Chưa có deadline',
    priority: subtask.priority ?? 'MEDIUM',
    status: subtask.status ?? 'TODO'
  });
}

const assignments = Object.values(assignmentMap);

return assignments.map((assignment) => {
  const subtaskLines = assignment.subtasks.length
    ? assignment.subtasks
        .map((s, index) => {
          return (index + 1) + '. ' + s.title
            + lineBreak + '   Deadline: ' + s.deadlineDisplay
            + lineBreak + '   Priority: ' + s.priority
            + lineBreak + '   Status: ' + s.status;
        })
        .join(lineBreak + lineBreak)
    : 'Bạn không có task con riêng trong task này.';

  return {
    json: {
      taskId: task.taskId,
      taskName: task.taskName,
      taskDescription: task.taskDescription,
      adminNote: task.adminNote,
      sourceInput: task.sourceInput,

      managerEmail: task.managerEmail,
      ownerName: task.ownerName,

      priority: task.priority,
      status: task.status,

      deadline: task.deadline,
      deadlineDisplay: task.deadlineDisplay,

      eventType: task.eventType,
      eventMessage: task.eventMessage,

      recipientEmail: assignment.email,
      isMainAssignee: assignment.isMainAssignee,
      assignedSubtasks: assignment.subtasks,
      subtaskCount: assignment.subtasks.length,
      subtaskLines,

      roleText: assignment.isMainAssignee
        ? 'Bạn là người phụ trách chính của task cha.'
        : 'Bạn là thành viên được giao task con.',

      receivedAt: task.receivedAt
    }
  };
});

const body = $json.body ?? $json;

const clampCount = (value) => {
  const number = Number(value);
  if (!Number.isFinite(number)) return 3;
  return Math.min(Math.max(Math.round(number), 1), 8);
};

const normalizePriority = (value) => {
  const priority = String(value || 'MEDIUM').trim().toUpperCase();
  return ['HIGH', 'MEDIUM', 'LOW'].includes(priority) ? priority : 'MEDIUM';
};

const taskName = String(body.taskName || body.title || '').trim();
const taskDescription = String(body.taskDescription || body.description || '').trim();
const adminNote = String(body.adminNote || body.note || '').trim();
const sourceInput = String(body.sourceInput || '').trim();
const desiredCount = clampCount(body.desiredCount || body.count || 3);
const priority = normalizePriority(body.priority);
const assigneeEmail = body.assigneeEmail || body.assignedTo || null;
const deadline = body.deadline || body.dueDate || body.endDate || null;

if (!taskName) {
  return [{
    json: {
      ok: false,
      error: 'taskName is required',
      subtasks: []
    }
  }];
}

const contextLines = [
  'Ban la tro ly quan ly du an. Hay chia task cha thanh cac subtask ro rang, co the giao viec truc tiep.',
  '',
  'THONG TIN TASK CHA:',
  'Ten task: ' + taskName,
  'Mo ta: ' + (taskDescription || 'Khong co'),
  'Ghi chu quan ly: ' + (adminNote || sourceInput || 'Khong co'),
  'Do uu tien task cha: ' + priority,
  'Deadline task cha: ' + (deadline || 'Chua co'),
  'Nguoi duoc giao mac dinh: ' + (assigneeEmail || 'Chua co'),
  '',
  'YEU CAU:',
  '- Tao dung ' + desiredCount + ' subtask.',
  '- Moi title phai la hanh dong cu the, ngan gon, tieng Viet, khong trung nhau.',
  '- Khong tao subtask mo ho nhu "Lam task" hoac "Xu ly cong viec".',
  '- Priority chi duoc la HIGH, MEDIUM, LOW. Khong cao hon priority task cha neu khong that su can thiet.',
  '- Status luon la TODO.',
  '- positionIndex bat dau tu 0.',
  '',
  'TRA VE DUY NHAT JSON object dung format nay, khong markdown, khong giai thich:',
  '{"subtasks":[{"title":"...","priority":"MEDIUM","status":"TODO","positionIndex":0}]}'
];

return [{
  json: {
    ok: true,
    taskName,
    taskDescription,
    adminNote,
    sourceInput,
    desiredCount,
    priority,
    assigneeEmail,
    deadline,
    prompt: contextLines.join('\n')
  }
}];

const original = $items('Normalize AI Request')[0]?.json ?? {};
const rawOutput = $json.output ?? $json.text ?? $json.response ?? '';
const fence = String.fromCharCode(96).repeat(3);

const stripFence = (value) => {
  let text = String(value || '').trim();
  const lower = text.toLowerCase();

  if (lower.startsWith(fence + 'json')) {
    text = text.slice((fence + 'json').length).trim();
  } else if (text.startsWith(fence)) {
    text = text.slice(fence.length).trim();
  }

  if (text.endsWith(fence)) {
    text = text.slice(0, -fence.length).trim();
  }

  return text;
};

const normalizePriority = (value) => {
  const priority = String(value || original.priority || 'MEDIUM').trim().toUpperCase();
  if (!['HIGH', 'MEDIUM', 'LOW'].includes(priority)) return original.priority || 'MEDIUM';

  const rank = { LOW: 1, MEDIUM: 2, HIGH: 3 };
  const parentPriority = original.priority || 'MEDIUM';
  return rank[priority] > rank[parentPriority] ? parentPriority : priority;
};

let parsed = null;
try {
  parsed = JSON.parse(stripFence(rawOutput));
} catch (error) {
  parsed = null;
}

const rows = Array.isArray(parsed) ? parsed : (Array.isArray(parsed?.subtasks) ? parsed.subtasks : []);
const seen = new Set();
const subtasks = [];

for (const row of rows) {
  const title = String(row?.title || row?.name || '').trim();
  const key = title.toLowerCase();

  if (!title || seen.has(key)) continue;
  seen.add(key);

  subtasks.push({
    title,
    assignedTo: row?.assignedTo || row?.assigneeEmail || original.assigneeEmail || null,
    deadline: row?.deadline || original.deadline || null,
    priority: normalizePriority(row?.priority),
    status: 'TODO',
    positionIndex: subtasks.length
  });

  if (subtasks.length >= original.desiredCount) break;
}

return [{
  json: {
    ...original,
    ok: subtasks.length > 0,
    needsFallback: subtasks.length === 0,
    subtasks,
    count: subtasks.length,
    rawOutput: String(rawOutput || '')
  }
}];

const original = $items('Normalize AI Request')[0]?.json ?? $json;
const desiredCount = Math.min(Math.max(Number(original.desiredCount || 3), 1), 8);
const titles = [
  'Phan tich yeu cau va pham vi cong viec',
  'Thiet ke phuong an xu ly chi tiet',
  'Trien khai phan viec chinh',
  'Kiem thu va ra soat ket qua',
