  'Theo doi phan hoi sau ban giao',
  'Toi uu va xu ly cac diem phat sinh',
  'Tong hop bao cao hoan thanh'
];

const subtasks = titles.slice(0, desiredCount).map((title, index) => ({
  title,
  assignedTo: original.assigneeEmail || null,
  deadline: original.deadline || null,
  priority: original.priority || 'MEDIUM',
  status: 'TODO',
  positionIndex: index
}));

return [{
  json: {
    ...original,
    ok: true,
    needsFallback: false,
    fallbackUsed: true,
